2291 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2292 |     function applyLocalPatch(content, ops) {
2293 |         let lines = content.split('\n');
2294 |         let logs = [];
2295 |         let success = true;
2296 | 
2297 |         if (typeof ops === 'string') {
2298 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2299 |         }
2300 | 
2301 |         ops.forEach(op => {
2302 |             if (op.action === 'comment') return;
2303 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2304 |             
2305 |             if (op.action === 'replace_block') {
2306 |                 // Strategy 1: Exact String Match (Fastest)
2307 |                 const currentStr = lines.join('\n');
2308 |                 if (currentStr.includes(op.find_block)) {
2309 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2310 |                     logs.push('Exact match applied');
2311 |                     return;
2312 |                 }
2313 | 
2314 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2315 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2316 |                 if (searchLines.length === 0) return;
2317 | 
2318 |                 let matchStart = -1;
2319 |                 let matchEnd = -1;
2320 | 
2321 |                 // Scan file lines
2322 |                 for (let i = 0; i < lines.length; i++) {
2323 |                     // If first line matches (ignoring whitespace)
2324 |                     if (lines[i].trim() === searchLines[0]) {
2325 |                         // Check subsequent lines
2326 |                         let allMatch = true;
2327 |                         let fileOffset = 0;
2328 |                         let searchOffset = 1;
2329 |                         
2330 |                         while (searchOffset < searchLines.length) {
2331 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2332 |                             const nextFile = lines[i + fileOffset + 1].trim();
2333 |                             // Skip empty lines in file if they aren't in search block
2334 |                             if (nextFile === '') {
2335 |                                 fileOffset++;
2336 |                                 continue;
2337 |                             }
2338 |                             if (nextFile !== searchLines[searchOffset]) {
2339 |                                 allMatch = false;
2340 |                                 break;
2341 |                             }
2342 |                             fileOffset++;
2343 |                             searchOffset++;
2344 |                         }
2345 | 
2346 |                         if (allMatch) {
2347 |                             matchStart = i;
2348 |                             matchEnd = i + fileOffset;
2349 |                             break;
2350 |                         }
2351 |                     }
2352 |                 }
2353 | 
2354 |                 if (matchStart !== -1) {
2355 |                     // Replace the range of lines
2356 |                     const replacement = op.replace_with.split('\n');
2357 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2358 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2359 |                 } else {
2360 |                     success = false;
2361 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2362 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2363 |                 }
2364 |             }
2365 |         });
2366 |         return { content: lines.join('\n'), success, logs };
2367 |     }
