5195 |     function formatBytes(bytes) {
5196 |         if (!bytes) return '0 B';
5197 |         const k = 1024;
5198 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5199 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5200 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5201 |     }
