7926 |     function extractTableNames(sql) {
7927 |         if (!sql) return [];
7928 |         const tables = [];
7929 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7930 |         
7931 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7932 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7933 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7934 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7935 | 
7936 |         let match;
7937 |         while ((match = fromRegex.exec(sql)) !== null) {
7938 |             const name = match[1];
7939 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7940 |                 tables.push(name);
7941 |             }
7942 |         }
7943 |         
7944 |         while ((match = metaRegex.exec(sql)) !== null) {
7945 |             const name = match[1];
7946 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7947 |                 tables.push(name);
7948 |             }
7949 |         }
7950 | 
7951 |         return tables;
7952 |     }
