7954 |     function convertToCSV(resultObj) {
7955 |         const data = resultObj.data || [];
7956 |         if (!data.length) return '';
7957 |         
7958 |         const tables = extractTableNames(resultObj.sql);
7959 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7960 | 
7961 |         const headers = Object.keys(data[0]);
7962 |         const rows = data.map(row => 
7963 |             headers.map(header => {
7964 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7965 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7966 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7967 |             }).join(',')
7968 |         );
7969 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7970 |     }
