function smartJSONParse(str) {
    // The Necromancer: Schema-Aware Reconstruction
    if (!str) return null;

    let raw = str.trim();

    // 1. Extract only the JSON part (ignore AI chatter)
    const firstBracket = raw.indexOf('[');
    const lastBracket = raw.lastIndexOf(']');
    if (firstBracket !== -1 && lastBracket !== -1) {
        raw = raw.substring(firstBracket, lastBracket + 1);
    }

    // 2. Kill trailing commas in arrays/objects
    raw = raw.replace(/,[\s\r\n]*([\}\]])/g, '$1');

    // 3. Handle truncated JSON (AI cut off)
    let openBrackets = (raw.match(/\[/g) || []).length;
    let closeBrackets = (raw.match(/\]/g) || []).length;
    while (openBrackets > closeBrackets) { raw += ']'; closeBrackets++; }

    let openBraces = (raw.match(/\{/g) || []).length;
    let closeBraces = (raw.match(/\}/g) || []).length;
    while (openBraces > closeBraces) { raw += '}'; closeBraces++; }

    // 4. THE MASTER FIX: Structural String Sanitization
    // We identify fields likely to contain code and protect them
    const codeFields = ['find_block', 'replace_with', 'content', 'text', 'explanation'];

    let processed = '';
    let inString = false;
    let currentField = '';
    let escapeNext = false;

    for (let i = 0; i < raw.length; i++) {
        let char = raw[i];

        if (char === '"' && !escapeNext) {
            inString = !inString;
            processed += char;
            continue;
        }

        if (inString) {
            if (char === '\\') {
                // If it's a standalone backslash not part of a known escape, double it
                const next = raw[i+1];
                if (!['"', '\\', '/', 'b', 'f', 'n', 'r', 't', 'u'].includes(next)) {
                    processed += '\\\\';
                } else {
                    processed += char;
                }
            } else if (char === '"' && !escapeNext) {
               // This is the quote-logic: is this a structural quote or content?
               // Look ahead: if followed by , " or } it's structural. Otherwise, content.
               const lookAhead = raw.substring(i + 1).trim();
               if (lookAhead.startsWith(',') || lookAhead.startsWith('}') || lookAhead.startsWith(']')) {
                   inString = false;
                   processed += char;
               } else {
                   processed += '\\"'; // Escape content quote
               }
            } else if (char === '\n' || char === '\r') {
                processed += '\\n'; // Neutralize literal newlines
            } else {
                processed += char;
            }
        } else {
            processed += char;
        }

        escapeNext = (char === '\\' && !escapeNext);
    }

    try {
        return JSON.parse(processed);
    } catch (e) {
        console.warn("Necromancer failed, attempting brute regex fallback...", e);
        // Final desperate attempt: swap common offenders
        const desperate = processed
            .replace(/\\"/g, '"') // unescape all
            .replace(/"/g, '\\"') // escape all
            .replace(/\\"([a-z0-9_]+)\\":/gi, '"$1":') // unescape keys
            .replace(/:[\s]*\\"([\s\S]*?)\\"[\s]*([,}\]])/g, ': "$1"$2'); // unescape simple values

        try { return JSON.parse(desperate); } catch (e3) { throw new Error("JSON is too corrupted to salvage."); }
    }
}

function manualJSONRepair() {
    const input = document.getElementById('json-input');
    try {
        const obj = smartJSONParse(input.value);
        input.value = JSON.stringify(obj, null, 2);
        saveState();
        showGlobalToast("âœ¨ JSON Structure Rebuilt");
    } catch (e) {
        showGlobalToast("â‌Œ Repair Failed: JSON too messy", true);
    }
}

