4164 |     async function executeRename() {
4165 |         const newPath = document.getElementById('rn-new-path').value.trim();
4166 |         const moveFolder = document.getElementById('rn-move-folder').checked;
4167 |         
4168 |         if (!newPath || newPath === currentRenamePath) return closeRenameModal();
4169 |         if (isPerformingAction) return;
4170 |         isPerformingAction = true;
4171 | 
4172 |         const getDir = (p) => p.substring(0, p.lastIndexOf('/') + 1);
4173 |         const oldDir = getDir(currentRenamePath);
4174 |         const newDir = getDir(newPath);
4175 | 
4176 |         showGlobalToast(moveFolder ? "Analyzing folder structure..." : "Preparing move...");
4177 | 
4178 |         try {
4179 |             let ops = [{ "action": "comment", "text": moveFolder ? `[Bulk Move] ${oldDir} -> ${newDir}` : `[Rename] ${currentRenamePath} -> ${newPath}` }];
4180 |             let filesToProcess = [];
4181 | 
4182 |             if (moveFolder && oldDir) {
4183 |                 // Find all siblings
4184 |                 filesToProcess = window.repoFiles.filter(f => f.path.startsWith(oldDir)).map(f => f.path);
4185 |             } else {
4186 |                 filesToProcess = [currentRenamePath];
4187 |             }
4188 | 
4189 |             // Concurrent Content Fetching
4190 |             const BATCH_SIZE = 5;
4191 |             for (let i = 0; i < filesToProcess.length; i += BATCH_SIZE) {
4192 |                 const batch = filesToProcess.slice(i, i + BATCH_SIZE);
4193 |                 const batchResults = await Promise.all(batch.map(async (path) => {
4194 |                     const res = await fetch(CONFIG.funcUrl, {
4195 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
