5203 |     function timeAgo(dateString) {
5204 |         const date = new Date(dateString);
5205 |         const now = new Date();
5206 |         const seconds = Math.floor((now - date) / 1000);
5207 |         if (seconds < 10) return 'just now';
5208 |         if (seconds < 60) return seconds + 's ago';
5209 |         const minutes = Math.floor(seconds / 60);
5210 |         if (minutes < 60) return minutes + 'm ago';
5211 |         const hours = Math.floor(minutes / 60);
5212 |         if (hours < 24) return hours + 'h ago';
5213 |         return date.toLocaleDateString();
5214 |     }
