2397 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2398 |     function applyLocalPatch(content, ops) {
2399 |         let lines = content.split('\n');
2400 |         let logs = [];
2401 |         let success = true;
2402 | 
2403 |         if (typeof ops === 'string') {
2404 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2405 |         }
2406 | 
2407 |         ops.forEach(op => {
2408 |             if (op.action === 'comment') return;
2409 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2410 |             
2411 |             if (op.action === 'replace_block') {
2412 |                 // Strategy 1: Exact String Match (Fastest)
2413 |                 const currentStr = lines.join('\n');
2414 |                 if (currentStr.includes(op.find_block)) {
2415 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2416 |                     logs.push('Exact match applied');
2417 |                     return;
2418 |                 }
2419 | 
2420 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2421 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2422 |                 if (searchLines.length === 0) return;
2423 | 
2424 |                 let matchStart = -1;
2425 |                 let matchEnd = -1;
2426 | 
2427 |                 // Scan file lines
2428 |                 for (let i = 0; i < lines.length; i++) {
2429 |                     // If first line matches (ignoring whitespace)
2430 |                     if (lines[i].trim() === searchLines[0]) {
2431 |                         // Check subsequent lines
2432 |                         let allMatch = true;
2433 |                         let fileOffset = 0;
2434 |                         let searchOffset = 1;
2435 |                         
2436 |                         while (searchOffset < searchLines.length) {
2437 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2438 |                             const nextFile = lines[i + fileOffset + 1].trim();
2439 |                             // Skip empty lines in file if they aren't in search block
2440 |                             if (nextFile === '') {
2441 |                                 fileOffset++;
2442 |                                 continue;
2443 |                             }
2444 |                             if (nextFile !== searchLines[searchOffset]) {
2445 |                                 allMatch = false;
2446 |                                 break;
2447 |                             }
2448 |                             fileOffset++;
2449 |                             searchOffset++;
2450 |                         }
2451 | 
2452 |                         if (allMatch) {
2453 |                             matchStart = i;
2454 |                             matchEnd = i + fileOffset;
2455 |                             break;
2456 |                         }
2457 |                     }
2458 |                 }
2459 | 
2460 |                 if (matchStart !== -1) {
2461 |                     // Replace the range of lines
2462 |                     const replacement = op.replace_with.split('\n');
2463 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2464 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2465 |                 } else {
2466 |                     success = false;
2467 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2468 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2469 |                 }
2470 |             }
2471 |         });
2472 |         return { content: lines.join('\n'), success, logs };
2473 |     }
