5301 |     function formatBytes(bytes) {
5302 |         if (!bytes) return '0 B';
5303 |         const k = 1024;
5304 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5305 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5306 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5307 |     }
