5309 |     function timeAgo(dateString) {
5310 |         const date = new Date(dateString);
5311 |         const now = new Date();
5312 |         const seconds = Math.floor((now - date) / 1000);
5313 |         if (seconds < 10) return 'just now';
5314 |         if (seconds < 60) return seconds + 's ago';
5315 |         const minutes = Math.floor(seconds / 60);
5316 |         if (minutes < 60) return minutes + 'm ago';
5317 |         const hours = Math.floor(minutes / 60);
5318 |         if (hours < 24) return hours + 'h ago';
5319 |         return date.toLocaleDateString();
5320 |     }
