8032 |     function extractTableNames(sql) {
8033 |         if (!sql) return [];
8034 |         const tables = [];
8035 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8036 |         
8037 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8038 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8039 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8040 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8041 | 
8042 |         let match;
8043 |         while ((match = fromRegex.exec(sql)) !== null) {
8044 |             const name = match[1];
8045 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8046 |                 tables.push(name);
8047 |             }
8048 |         }
8049 |         
8050 |         while ((match = metaRegex.exec(sql)) !== null) {
8051 |             const name = match[1];
8052 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8053 |                 tables.push(name);
8054 |             }
8055 |         }
8056 | 
8057 |         return tables;
8058 |     }
8059 | 
8060 |     function convertToCSV(resultObj) {
8061 |         const data = resultObj.data || [];
8062 |         if (!data.length) return '';
8063 |         
8064 |         const tables = extractTableNames(resultObj.sql);
8065 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8066 | 
8067 |         const headers = Object.keys(data[0]);
8068 |         const rows = data.map(row => 
8069 |             headers.map(header => {
8070 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8071 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8072 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8073 |             }).join(',')
8074 |         );
8075 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8076 |     }
